const claim = $json;
const opp = claim.opportunities ?? {};
return [{ json: { opportunity_slug: opp.slug, opportunity_id: claim.opportunity_id, claim_id: claim.id, title: opp.title, industry: opp.industry, niche: opp.niche, audience: opp.audience } }];

