  ]
}

parameters.jsCode:
const slug = $('Shape claim').first().json.opportunity_slug;
let payload;
try {
  const text = $input.first().json.content?.[0]?.text ?? '';
  const stripped = text.replace(/^```(?:json)?\n?/, '').replace(/```$/, '').trim();
  payload = JSON.parse(stripped);
} catch (e) {
  return [];
}
if (!Array.isArray(payload)) return [];
return payload
  .filter(s => s && s.url && s.title && s.published_at && s.source_type)
  .map(item => ({ json: { ...item, opportunity_slug: slug } }));
